const active_result = $('Phase A: Count active seeds').item.json;
const active_count = active_result[0]?.active_count || 0;
const mode = active_count < 30 ? 'aggressive_growth' : 'maintenance';
const target_new_seeds = mode === 'aggressive_growth' ? 15 : 8;

return [{
  json: {
    active_count: active_count,
    mode: mode,
    target_new_seeds: target_new_seeds,
    timestamp: new Date().toISOString()
  }
}];

// Aggregate Phase B discovery sources
const news_items = $('Phase B: Fetch recent news').item?.json || [];
const comp_items = $('Phase B: Fetch competitor activity').item?.json || [];
const topics_items = $('Phase B: Get top topics').item?.json || [];
const hashtags_result = $('Phase B: Get trending hashtags').item?.json || [];

const news_titles = news_items.map(n => n.title).join('; ') || 'none';
const comp_activities = comp_items.map(c => c.activity_text).slice(0, 5).join('; ') || 'none';
const top_topics = topics_items.map(t => t.topic_tag).join(', ') || 'security, privacy, browsers';
const hashtags_json = hashtags_result[0]?.value || '{}';
let hashtags_str = '';
try {
  const parsed = typeof hashtags_json === 'string' ? JSON.parse(hashtags_json) : hashtags_json;
  hashtags_str = Array.isArray(parsed) ? parsed.join(', ') : Object.keys(parsed).join(', ');
} catch (e) {
  hashtags_str = 'privacy, adblock, browser, security';
}

return [{
  json: {
    news_titles: news_titles,
    competitor_activities: comp_activities,
    top_topics: top_topics,
    hashtags: hashtags_str,
    sources_count: {
      news: news_items.length,
      competitors: comp_items.length,
      topics: topics_items.length
    }
  }
}];

// Build Gemini Pro prompt with strict brand/size guardrails
const sources = $json;
const target_seeds = $('Phase A: Diagnose mode').item.json.target_new_seeds || 15;
const hard_cap = Math.min(target_seeds, 20);

const prompt = `You are AdOff content strategist (browser ad-blocker extension). Generate ${hard_cap} BRAND-NEW content seeds based on:

**Top performing topics (extend these angles):**
${sources.top_topics}

**Recent news in ad/privacy/browser space:**
${sources.news_titles}

**Competitor moves (no direct brand naming, learn from tactics):**
${sources.competitor_activities}

**Trending hashtags (inspiration only):**
${sources.hashtags}

**HARD CONSTRAINTS (VIOLATION = rejection):**
- NEVER mention YouTube, Google, Facebook, Instagram, Amazon, TikTok, Twitch, Reddit, Twitter/X by name. Use generic terms: 'piattaforme video', 'motori ricerca', 'social media', 'e-commerce', etc.
- NEVER mention '149 KB' or any size '149', '138', '150' variants
- Never use hardcoded brand names in seeds
- Voice: energica, brillante, diretta, anti-establishment
- All in Italian language

**Mix required:**
- 30% educational (how-tos, features, technical)
- 30% emotional (frustration with ads, data privacy concerns)
- 20% comparative (without brand names: 'unlike competitors...')
- 20% tactical (quick tips, workarounds)

**Output format (JSON only, no markdown):**
{"seeds": [{"seed": "string 5-15 parole", "angle": "educational|emotional|comparative|tactical", "topic_tag": "max 20 chars", "estimated_engagement_score": 0-100, "why_now": "1-2 sentence justification"}]}`;

return [{
  json: {
    model: 'gemini-2.0-flash-exp',
    prompt: prompt,
    temperature: 0.7,
    max_tokens: 2000,
    hard_cap: hard_cap
  }
}];

// Extract text from Gemini response
let text_response = '';
try {
  const candidates = $json.candidates || [];
  if (candidates.length > 0) {
    const first_candidate = candidates[0];
    const content = first_candidate.content || {};
    const parts = content.parts || [];
    if (parts.length > 0) {
      text_response = parts[0].text || '';
    }
  }
} catch (e) {
  text_response = '';
}

let parsed_seeds = [];
if (text_response) {
  try {
    const json_match = text_response.match(/\{[\s\S]*\}/);
    if (json_match) {
      const obj = JSON.parse(json_match[0]);
      parsed_seeds = obj.seeds || [];
    }
  } catch (e) {
    parsed_seeds = [];
  }
}

return [{
  json: {
    raw_response: text_response,
    parsed_seeds_count: parsed_seeds.length,
    seeds: parsed_seeds
  }
}];

// Phase D: Brand guard + dedup filter
const brand_pattern = /youtube|google|facebook|instagram|tiktok|amazon|twitch|reddit|twitter|x\.com|linkedin/gi;
const size_pattern = /149\s?kb|138\s?kb|150\s?kb|\b149\b|\b138\b|\b150\b/gi;
const seeds = $json.seeds || [];

const filtered = [];
const violations = [];

for (const seed_obj of seeds) {
  const seed_text = (seed_obj.seed || '').toLowerCase();
  const topic = (seed_obj.topic_tag || '').toLowerCase();

  let has_brand_violation = brand_pattern.test(seed_text) || brand_pattern.test(topic);
  let has_size_violation = size_pattern.test(seed_text) || size_pattern.test(topic);

  if (has_brand_violation || has_size_violation) {
    violations.push({
      seed: seed_obj.seed,
      reason: has_brand_violation ? 'brand_name_found' : (has_size_violation ? 'size_leak_found' : 'unknown'),
      seed_text: seed_text
    });
  } else {
    filtered.push(seed_obj);
  }
}

// Dedup by lowercase + stopword removal simple comparison
const deduplicated = [];
const seen_hashes = new Set();

for (const s of filtered) {
  const normalized = s.seed
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .split(/\s+/)
    .filter(w => !['il', 'lo', 'la', 'di', 'da', 'a', 'e', 'o', 'un', 'una', 'come', 'per', 'che'].includes(w))
    .sort()
    .join('|');

  if (!seen_hashes.has(normalized)) {
    seen_hashes.add(normalized);
    deduplicated.push(s);
  }
}

return [{
  json: {
    total_generated: seeds.length,
    after_brand_guard: filtered.length,
    after_dedup: deduplicated.length,
    violations: violations,
    final_seeds: deduplicated.slice(0, 20) // hard cap 20
  }
}];

// Phase D: Insert new seeds into DB
const final_seeds = $json.final_seeds || [];
const inserts = [];

for (const s of final_seeds) {
  inserts.push({
    seed: s.seed,
    angle: s.angle || 'tactical',
    topic_tag: (s.topic_tag || 'other').substring(0, 20),
    used_count: 0,
    perf_score: 0.5, // neutral start
    active: true,
    created_at: new Date().toISOString(),
    last_used: null,
    estimated_score: s.estimated_engagement_score || 50
  });
}

return inserts.map(insert => ({ json: insert }));

// Phase F: Build Telegram report
const active_count = $('Phase A: Diagnose mode').item.json.active_count;
const tired_seeds = $('Phase A: Find tired seeds').item.json || [];
const filter_result = $('Phase D: Filter & dedup').item.json;
const final_count = filter_result.final_seeds?.length || 0;

const report_date = new Date().toISOString().split('T')[0];
const deactivated_count = tired_seeds.length;

// Count angles in final seeds
const final_seeds = filter_result.final_seeds || [];
const angle_counts = {};
for (const s of final_seeds) {
  const angle = s.angle || 'other';
  angle_counts[angle] = (angle_counts[angle] || 0) + 1;
}

const angle_summary = Object.entries(angle_counts)
  .map(([a, c]) => `${c} ${a}`)
  .join(', ');

const top_seed = final_seeds[0]?.seed || 'none';

const message = `Seed Refresher ${report_date}:\n${active_count} seed attivi, ${deactivated_count} disattivati (tired/low-perf), ${final_count} nuovi generati (${angle_summary || 'mixed'}).\nTop new: '${top_seed}'`;

return [{
  json: {
    report: message,
    stats: {
      active_before: active_count,
      deactivated: deactivated_count,
      new_generated: final_count,
      angles: angle_counts
    }
  }
}];

// Final summary
const diagnose = $('Phase A: Diagnose mode').item.json;
const filter = $('Phase D: Filter & dedup').item.json;
const report = $('Phase F: Build Telegram report').item.json;

return [{
  json: {
    status: 'success',
    timestamp: new Date().toISOString(),
    workflow_id: 'w47-content-seed-refresher',
    phase_a: {
      active_count: diagnose.active_count,
      mode: diagnose.mode,
      tired_deactivated: filter.total_generated > 0 ? 'processed' : 0
    },
    phase_b: {
      sources_discovered: diagnose.sources_count || {}
    },
    phase_c: {
      gemini_generated: filter.total_generated
    },
    phase_d: {
      after_brand_guard: filter.after_brand_guard,
      after_dedup: filter.after_dedup,
      inserted: filter.final_seeds?.length || 0,
      violations: filter.violations?.length || 0
    },
    phase_e: {
      news_marked_used: 'done'
    },
    phase_f: {
      telegram_sent: true,
      report_summary: report.stats
    }
  }
}];
